INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '一质点沿直线运动，其位移-时间图像是一条倾斜的直线，则该质点做', '["A. 匀速直线运动", "B. 匀加速直线运动", "C. 变加速直线运动", "D. 静止"]', '[""A""]', 's-t图像为倾斜直线说明位移随时间均匀变化，速度恒定，为匀速直线运动。', 'easy', (SELECT id FROM knowledge_point WHERE name='运动' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='运动' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', '一辆汽车以72km/h的速度匀速行驶，5s内通过的路程为______m。', '[]', '[""100""]', 'v=72km/h=20m/s，s=vt=20×5=100m。', 'easy', (SELECT id FROM knowledge_point WHERE name='运动' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='运动' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'short_answer', '一质点做匀变速直线运动，初速度为2m/s，加速度为3m/s²。求：(1)3s末的速度；(2)前3s内的位移。', '[]', '[""(1)11m/s；(2)19.5m""]', '(1)v=v₀+at=2+3×3=11m/s。(2)s=v₀t+½at²=2×3+0.5×3×9=6+13.5=19.5m。', 'medium', (SELECT id FROM knowledge_point WHERE name='运动' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='运动' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '关于惯性，下列说法正确的是', '["A. 物体速度越大惯性越大", "B. 物体质量越大惯性越大", "C. 物体受力越大惯性越大", "D. 物体在太空中没有惯性"]', '[""B""]', '惯性大小只由质量决定，与速度、受力、空间位置无关。', 'easy', (SELECT id FROM knowledge_point WHERE name='牛顿定律' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='牛顿定律' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '质量为2kg的物体在水平面上受F=6N的水平拉力，物体与水平面间的动摩擦因数为0.2，则物体的加速度大小为(g取10m/s²)', '["A. 1m/s²", "B. 2m/s²", "C. 3m/s²", "D. 4m/s²"]', '[""A""]', 'f=μmg=0.2×2×10=4N，F合=F-f=2N，a=F合/m=1m/s²。', 'medium', (SELECT id FROM knowledge_point WHERE name='牛顿定律' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='牛顿定律' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'multi_choice', '关于牛顿第三定律，下列说法正确的有', '["A. 作用力与反作用力大小相等", "B. 作用力与反作用力作用在同一物体上", "C. 作用力与反作用力性质相同", "D. 作用力与反作用力同时产生、同时消失"]', '["["A", "C", "D"]"]', '作用力和反作用力分别作用在不同物体上，B错误。', 'medium', (SELECT id FROM knowledge_point WHERE name='牛顿定律' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='牛顿定律' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', '物体放在倾角为θ的固定斜面上，恰好能沿斜面匀速下滑，则物体与斜面间的动摩擦因数μ=______。', '[]', '[""tanθ""]', '匀速下滑时mgsinθ=μmgcosθ，μ=tanθ。', 'hard', (SELECT id FROM knowledge_point WHERE name='牛顿定律' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='牛顿定律' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'short_answer', '质量4kg物体静止在水平面上，水平拉力F=2t(N)，物体与水平面间动摩擦因数0.1，g=10m/s²。(1)物体开始运动的时间；(2)t=5s时物体的速度。', '[]', '[""(1)2s；(2)约2.25m/s""]', '(1)f=μmg=4N，物体开始运动需F≥f即2t≥4，t≥2s。(2)2~5s内F合=2t-4，a=(2t-4)/4=t/2-1。v=∫(t/2-1)dt从2到5=[t²/4-t]₂⁵=(6.25-5)-(1-2)=2.25m/s。', 'hard', (SELECT id FROM knowledge_point WHERE name='牛顿定律' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='牛顿定律' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '关于曲线运动，下列说法正确的是', '["A. 曲线运动的速度大小一定变化", "B. 曲线运动的速度方向一定变化", "C. 曲线运动的加速度一定变化", "D. 曲线运动一定是非匀变速运动"]', '[""B""]', '曲线运动速度方向沿切线不断变化。速度大小可以不变(匀速圆周运动)，加速度可以不变(平抛运动)。', 'easy', (SELECT id FROM knowledge_point WHERE name='曲线运动' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='曲线运动' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '从同一高度以相同速率分别竖直上抛、平抛和竖直下抛三个小球，不计空气阻力，则', '["A. 三球落地时速度相同", "B. 三球落地时速率相同", "C. 三球空中运动时间相同", "D. 三球水平位移相同"]', '[""B""]', '由机械能守恒，三球落地速率相等但速度方向不同，时间也各不相同。', 'medium', (SELECT id FROM knowledge_point WHERE name='曲线运动' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='曲线运动' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', '物体以10m/s的初速度水平抛出，落地时速度方向与水平方向夹角为45°，则抛出点高度为______m。(g取10m/s²)', '[]', '[""5""]', 'tan45°=vy/vx=1→vy=10m/s。vy²=2gh→h=5m。', 'medium', (SELECT id FROM knowledge_point WHERE name='曲线运动' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='曲线运动' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '关于开普勒行星运动定律，下列说法正确的是', '["A. 所有行星绕太阳运动的轨道都是圆", "B. 行星离太阳越近运行周期越长", "C. 第三定律中的k值与行星质量有关", "D. 行星与太阳的连线在相等时间内扫过相等面积"]', '[""D""]', 'D为开普勒第二定律。轨道为椭圆(A错)，越近周期越短(B错)，k值与中心天体有关(C错)。', 'easy', (SELECT id FROM knowledge_point WHERE name='万有引力' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='万有引力' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '地球表面重力加速度为g，半径为R。一颗人造卫星在距地面高度为R的圆轨道上运行，其向心加速度为', '["A. g/4", "B. g/2", "C. g", "D. g/8"]', '[""A""]', '距地心2R，g''=GM/(2R)²=g/4。', 'medium', (SELECT id FROM knowledge_point WHERE name='万有引力' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='万有引力' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', '已知地球质量为M，半径为R，万有引力常量为G，则地球的第一宇宙速度为______。', '[]', '[""√(GM/R)""]', '由GMm/R²=mv²/R得v=√(GM/R)。', 'medium', (SELECT id FROM knowledge_point WHERE name='万有引力' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='万有引力' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '关于功，下列说法正确的是', '["A. 功是能量转化的量度", "B. 摩擦力一定做负功", "C. 作用力做正功时反作用力一定做负功", "D. 功越大物体的能量越大"]', '[""A""]', '功是能量转化的量度。摩擦力可做正功(传送带)，作用力与反作用力做功无必然联系。', 'easy', (SELECT id FROM knowledge_point WHERE name='机械能' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='机械能' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '质量为m的物体从离地面H高处自由落下，以地面为零势能面。当物体的动能等于重力势能时，物体离地面的高度为', '["A. H/4", "B. H/2", "C. 3H/4", "D. H/3"]', '[""B""]', 'mg(H-h)=mgh→H-h=h→h=H/2。', 'medium', (SELECT id FROM knowledge_point WHERE name='机械能' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='机械能' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'multi_choice', '关于机械能守恒的条件，下列说法正确的有', '["A. 只有重力做功时机械能守恒", "B. 只有重力和弹力做功时机械能守恒", "C. 不受任何外力时机械能守恒", "D. 合外力为零时机械能一定守恒"]', '["["A", "B", "C"]"]', '合外力为零时动能不变但势能可变(如匀速上升)，D错误。', 'medium', (SELECT id FROM knowledge_point WHERE name='机械能' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='机械能' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'short_answer', '质量2kg物体从倾角30°斜面顶端由静止滑下，斜面长4m，动摩擦因数0.25，g=10m/s²。(1)物体滑到底端的速度；(2)损失的机械能。', '[]', '[""(1)约4.76m/s；(2)约17.3J""]', 'h=4×sin30°=2m，Wg=40J。f=0.25×2×10×cos30°≈4.33N，Wf≈17.32J。½mv²=22.68→v≈4.76m/s。损失机械能=Wf≈17.3J。', 'hard', (SELECT id FROM knowledge_point WHERE name='机械能' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='机械能' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '关于电场强度的定义式E=F/q，下列说法正确的是', '["A. E与F成正比与q成反比", "B. E的方向与正电荷受力方向相同", "C. q是产生电场的电荷", "D. 此式只适用于点电荷电场"]', '[""B""]', 'E由电场本身决定与试探电荷无关。q是试探电荷而非场源。B正确。', 'easy', (SELECT id FROM knowledge_point WHERE name='电场' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='电场' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '两个相同金属小球，分别带有+Q和-3Q的电荷，相距r时静电力大小为F。将它们接触后放回原处，静电力大小变为', '["A. F/3", "B. F/9", "C. 3F", "D. F"]', '[""A""]', '接触后各带(-3Q+Q)/2=-Q。F=3kQ²/r²，F''=kQ²/r²=F/3。', 'medium', (SELECT id FROM knowledge_point WHERE name='电场' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='电场' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', '在匀强电场中，将电荷量为2×10⁻⁹C的正电荷从A点移到B点，电场力做功4×10⁻⁷J，则UAB=______V。', '[]', '[""200""]', 'U=W/q=4×10⁻⁷/(2×10⁻⁹)=200V。', 'medium', (SELECT id FROM knowledge_point WHERE name='电场' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='电场' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'short_answer', '平行板电容器充电后与电源断开，负极板接地。在两极板间有一正电荷固定在P点。若将负极板向下移动一小段距离，分析：(1)极板间电场强度的变化；(2)P点电势的变化；(3)正电荷在P点电势能的变化。', '[]', '[""(1)不变；(2)升高；(3)增大""]', '断开电源Q不变，均匀场E=4πkQ/S与板距无关。d增大，U=Ed增大。P距正极板距离不变但负极下移，P点电势升高。正电荷Ep=qφ增大。', 'hard', (SELECT id FROM knowledge_point WHERE name='电场' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='电场' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '一个标有220V 100W的灯泡，正常工作时的电阻为', '["A. 484Ω", "B. 242Ω", "C. 121Ω", "D. 22Ω"]', '[""A""]', 'R=U²/P=220²/100=484Ω。', 'easy', (SELECT id FROM knowledge_point WHERE name='电流' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='电流' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', 'R₁=2Ω,R₂=3Ω,R₃=6Ω三者并联后接在电压为U的电源上，通过R₁、R₂、R₃的电流之比为', '["A. 1:2:3", "B. 3:2:1", "C. 6:3:2", "D. 2:3:6"]', '[""B""]', '并联电压相等，I₁:I₂:I₃=1/2:1/3:1/6=3:2:1。', 'medium', (SELECT id FROM knowledge_point WHERE name='电流' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='电流' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', '电源电动势为6V，内阻为1Ω，外接5Ω电阻构成闭合回路，则路端电压为______V。', '[]', '[""5""]', 'I=E/(R+r)=6/6=1A，U=IR=1×5=5V。', 'medium', (SELECT id FROM knowledge_point WHERE name='电流' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='电流' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '关于磁感线，下列说法正确的是', '["A. 磁感线是真实存在的曲线", "B. 磁感线从N极出发终止于S极", "C. 磁感线是闭合曲线", "D. 两条磁感线可以相交"]', '[""C""]', '磁感线是假想的闭合曲线。外部N到S，内部S到N形成闭合回线。不相交。', 'easy', (SELECT id FROM knowledge_point WHERE name='磁场' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='磁场' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '带电粒子以速度v垂直进入磁感应强度为B的匀强磁场中做匀速圆周运动，半径为R。若速度变为2v，磁感应强度变为B/2，则半径变为', '["A. R/4", "B. R/2", "C. 2R", "D. 4R"]', '[""D""]', 'R=mv/(qB)，R''=m·2v/(q·B/2)=4mv/(qB)=4R。', 'medium', (SELECT id FROM knowledge_point WHERE name='磁场' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='磁场' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', '一根长0.5m的直导线通有2A电流，放在磁感应强度为0.4T的匀强磁场中，导线与磁场方向垂直时，安培力大小为______N。', '[]', '[""0.4""]', 'F=BIL=0.4×2×0.5=0.4N。', 'medium', (SELECT id FROM knowledge_point WHERE name='磁场' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='磁场' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '关于电磁感应现象，下列说法正确的是', '["A. 导体在磁场中运动就产生感应电流", "B. 穿过闭合回路的磁通量变化就产生感应电流", "C. 感应电流的磁场方向总是与原磁场方向相反", "D. 感应电动势的大小与磁通量成正比"]', '[""B""]', '产生感应电流的条件是闭合回路+磁通量变化。C遵循楞次定律(增反减同)。D中E=nΔΦ/Δt。', 'easy', (SELECT id FROM knowledge_point WHERE name='电磁感应' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='电磁感应' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '一根导体棒在匀强磁场中做切割磁感线运动，下列哪种情况产生的感应电动势最大', '["A. 导体棒平行于磁场方向运动", "B. 导体棒垂直于磁场方向运动，且速度垂直棒和磁场", "C. 导体棒与磁场方向成45°角运动", "D. 三种情况相同"]', '[""B""]', 'E=BLvsinθ，B描述B⊥L且v⊥L且B⊥v，sinθ=1达到最大值。', 'medium', (SELECT id FROM knowledge_point WHERE name='电磁感应' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='电磁感应' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', '一个匝数为100的线圈，穿过它的磁通量在0.1s内从0.02Wb均匀减小到0，则线圈中产生的感应电动势为______V。', '[]', '[""20""]', 'E=n|ΔΦ/Δt|=100×0.02/0.1=20V。', 'medium', (SELECT id FROM knowledge_point WHERE name='电磁感应' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='电磁感应' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'short_answer', '两根光滑平行金属导轨间距L=0.5m，与水平面成30°角放置，导轨上端接有电阻R=2Ω，导轨电阻不计。质量m=0.1kg的金属棒垂直放在导轨上，匀强磁场B=0.4T垂直导轨平面向上。金属棒从静止释放沿导轨下滑。(1)求金属棒的最大速度；(2)当v=5m/s时，求棒中的电流。(g=10m/s²)', '[]', '[""(1)25m/s；(2)0.5A""]', '(1)达最大速度时mgsin30°=BIL，I=BLv/R→mgsin30°=B²L²v/R。0.5=0.16×0.25v/2=0.02v→v=25m/s。(2)I=BLv/R=0.4×0.5×5/2=0.5A。', 'hard', (SELECT id FROM knowledge_point WHERE name='电磁感应' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='电磁感应' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '关于布朗运动，下列说法正确的是', '["A. 布朗运动是液体分子的无规则运动", "B. 布朗运动是悬浮微粒的无规则运动", "C. 温度越低布朗运动越剧烈", "D. 颗粒越大布朗运动越明显"]', '[""B""]', '布朗运动是悬浮微粒(不是分子)的无规则运动，反映液体分子运动。温度越高越剧烈。', 'easy', (SELECT id FROM knowledge_point WHERE name='热学' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='热学' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', '一定质量的理想气体从状态A(p₁,V₁,T₁)经等温膨胀到状态B(p₂,V₂,T₂)，则T₁______T₂。(填大于、小于或等于)', '[]', '[""等于""]', '等温过程温度不变。', 'medium', (SELECT id FROM knowledge_point WHERE name='热学' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='热学' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'short_answer', '理想气体从状态A变到B，p-V图中AB为一条直线。若TA=300K，A(p₀,V₀),B(2p₀,2V₀)。求：(1)TB；(2)气体从A到B对外做的功。', '[]', '[""(1)1200K；(2)1.5p₀V₀""]', '(1)TB/TA=pBVB/(pAVA)=4→TB=1200K。(2)W=梯形面积=½(p₀+2p₀)(2V₀-V₀)=1.5p₀V₀。', 'hard', (SELECT id FROM knowledge_point WHERE name='热学' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='热学' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'true_false', '判断：物体所受合外力越大，加速度越大。', '[]', '[""T""]', '由F=ma，质量一定时F越大a越大。', 'easy', (SELECT id FROM knowledge_point WHERE name='牛顿定律' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='牛顿定律' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'true_false', '判断：重力做功与物体运动的路径有关。', '[]', '[""F""]', '重力是保守力，做功只与初末位置高度差有关。', 'easy', (SELECT id FROM knowledge_point WHERE name='机械能' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='机械能' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'true_false', '判断：电场中电势越高的地方，电势能一定越大。', '[]', '[""F""]', 'Ep=qφ，正电荷在电势高处电势能大，负电荷则相反。', 'medium', (SELECT id FROM knowledge_point WHERE name='电场' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='电场' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'true_false', '判断：感应电流的磁场总是阻碍引起感应电流的磁通量变化。', '[]', '[""T""]', '这是楞次定律的完整表述。', 'medium', (SELECT id FROM knowledge_point WHERE name='电磁感应' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='电磁感应' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'multi_choice', '关于平抛运动，下列说法正确的有', '["A. 是匀变速曲线运动", "B. 水平位移由初速度和高度共同决定", "C. 相等时间内速度变化量相同", "D. 轨迹是抛物线"]', '["["A", "B", "C", "D"]"]', '只受重力a=g恒定→匀变速曲线运动A对。x=v₀√(2h/g)，B对。Δv=gΔt恒定，C对。轨迹y=gx²/(2v₀²)是抛物线D对。', 'medium', (SELECT id FROM knowledge_point WHERE name='曲线运动' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='曲线运动' AND subject='physics');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'true_false', '判断：温度是分子平均动能的标志。', '[]', '[""T""]', '温度越高，分子热运动越剧烈，分子平均动能越大。', 'easy', (SELECT id FROM knowledge_point WHERE name='热学' AND subject='physics' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='热学' AND subject='physics');
